def minimizeError(prices, target):
    import math
    res = []
    for p in prices:
        n = float(p)
        if math.floor(n) != math.ceil(n):
            res.append((math.ceil(n) - n, n - math.floor(n), math.floor(n), math.ceil(n)))
        else:
            target -= int(n)
    if target < 0 or target > len(res): return "-1"
    res.sort(key=lambda x: x[0] - x[1])
    ans = sum(x[0] for x in res[:target]) + sum(x[1] for x in res[target:])
    return "{:.3f}".format(ans)

